INSERT INTO tests (id, name, joint, purpose, protocol, positive, negative, youtubeUrl, thumbnailUrl) VALUES 
(1, 'Trendelenburg’s Sign', 'GLUTE MED', 'Weakness in Glute Med', 'CL standing, raise on foot & see if movement in hip', 'If pelvis drops on non-weight bearing side', 'Diagnostic criteria not met for Trendelenburg’s Sign', 'https://www.youtube.com/watch?v=uT_MreioV4M', 'https://img.youtube.com/vi/uT_MreioV4M/maxresdefault.jpg'),
(2, 'Hip Quadrant Scouring', 'HIP', 'JT capsule tightness, osteophyte formation, general hip pathologies', 'CL supine, flex & adduct hip, move knee in “rainbow” arcing formation', 'Crepitus, bumping, grinding, clunking', 'Diagnostic criteria not met for Hip Quadrant Scouring', 'https://www.youtube.com/watch?v=KmsX9fG_3pM', 'https://img.youtube.com/vi/KmsX9fG_3pM/maxresdefault.jpg'),
(3, 'Thomas Test', 'HIP', 'Hip flexor contracture', 'CL supine at end of table, bring both knees to chest, lower 1 leg', 'If leg is raised off table', 'Diagnostic criteria not met for Thomas Test', 'https://www.youtube.com/watch?v=04G2S9Y-m_k', 'https://img.youtube.com/vi/04G2S9Y-m_k/maxresdefault.jpg'),
(4, 'Pace Abduction', 'PIRIFORMIS', 'Strength of piriformis, TrP in piriformis', 'CL seated, legs bent off table, hands on outside of thighs, ask CL to press knees out against resistance', 'Weakness – unable to push hands apart, pain = TrP', 'Diagnostic criteria not met for Pace Abduction', 'https://www.youtube.com/watch?v=M6xre8v7Eig', 'https://img.youtube.com/vi/M6xre8v7Eig/maxresdefault.jpg'),
(5, 'Piriformis Length Test', 'PIRIFORMIS', 'Piriformis length', 'CL prone, bend legs to 90°, knees together. Keeping knees together, move feet apart', 'Compare bilaterally for reduced ROM', 'Diagnostic criteria not met for Piriformis Length Test', 'https://www.youtube.com/watch?v=f2Iis3f8Aiw', 'https://img.youtube.com/vi/f2Iis3f8Aiw/maxresdefault.jpg'),
(6, 'Gapping', 'SI JOINT', 'SI joint dysfunction, transverse ant. ligament', 'CL supine, crosshands on ASIS, push down and around (not directly down)', 'Pain in glutes or posterior leg', 'Diagnostic criteria not met for Gapping', 'https://www.youtube.com/watch?v=W1pD7XfLwM0', 'https://img.youtube.com/vi/W1pD7XfLwM0/maxresdefault.jpg'),
(7, 'Gillet’s – SI Joint Motion', 'SI JOINT', 'SI joint dysfunction movement/mobility', 'CL standing, 1 thumb on PSIS, 1 thumb on sacrum. CL lifts leg (PSIS thumb side)', 'If PSIS thumb moves up or doesn’t move', 'Diagnostic criteria not met for Gillet’s – SI Joint Motion', 'https://www.youtube.com/watch?v=TmqKj_K-Nio', 'https://img.youtube.com/vi/TmqKj_K-Nio/maxresdefault.jpg'),
(8, 'Squish', 'SI JOINT', 'SI joint dysfunction, transverse post. ligament', 'CL supine, hands on ASIS/crest press in and down', 'Pain in SI region', 'Diagnostic criteria not met for Squish', 'https://www.youtube.com/watch?v=o-eH-85T_3E', 'https://img.youtube.com/vi/o-eH-85T_3E/maxresdefault.jpg'),
(9, 'Ely’s – Rec. Fem, Nachlas – SI & LS', 'SI JOINT', 'Contracture of Rec. Fem & SI hypomobility, LS pathology', 'CL prone, bend leg; if hip pops up before 90° = SI joint; if pops midway to glute = Rec. fem; if pain in low back = LS pathology', 'Pain depending on structure involved', 'Diagnostic criteria not met for Ely’s – Rec. Fem, Nachlas – SI & LS', 'https://www.youtube.com/watch?v=_qf2yQj2k8E', 'https://img.youtube.com/vi/_qf2yQj2k8E/maxresdefault.jpg'),
(10, 'Faber / Figure 4 / Patrick’s', 'SI JOINT', 'Dysfunction at hip/SI joint, tightness of Psoas & hip mm', 'CL supine, place leg in figure 4 (foot just above knee). Apply pressure', 'Pain in SI jt/glutes or front of hip = SI dysfunction; leg remains above other leg = hip pathology or psoas issues', 'Diagnostic criteria not met for Faber / Figure 4 / Patrick’s', 'https://www.youtube.com/watch?v=rG-t12S-8Bw', 'https://img.youtube.com/vi/rG-t12S-8Bw/maxresdefault.jpg'),
(11, 'Gaenslen’s', 'SI JOINT', 'Integrity of anterior SI ligament & hip pathology', 'CL supine near edge of table, hold one hip off table. Bring both knees to chest, hold back of thigh & lower outside leg', 'Sharp local pain to SI joint', 'Diagnostic criteria not met for Gaenslen’s', 'https://www.youtube.com/watch?v=R0_Jc006Jj4', 'https://img.youtube.com/vi/R0_Jc006Jj4/maxresdefault.jpg'),
(12, 'Sacroiliac Rocking', 'SI JOINT', 'SI joint dysfunction, lesions of sacrotuberous ligament', 'CL supine. Take knee toward opposite shoulder. Rock forward/backward then apply direct pressure down', 'Pain in sacroiliac joint area', 'Diagnostic criteria not met for Sacroiliac Rocking', 'https://www.youtube.com/watch?v=SedsvjW22_Y', 'https://img.youtube.com/vi/SedsvjW22_Y/maxresdefault.jpg'),
(13, 'Yeoman’s', 'SI JOINT', 'SI joint dysfunction, lumbar pathology, femoral nerve stretch', 'CL prone, one hand on posterior iliac crest to prevent hip lifting. Bend leg to 90°, lift leg', 'Pain in SI region, lumbar region, numbness anterior thigh', 'Diagnostic criteria not met for Yeoman’s', 'https://www.youtube.com/watch?v=BwzJd6tZ3w8', 'https://img.youtube.com/vi/BwzJd6tZ3w8/maxresdefault.jpg'),
(14, 'Allen’s Test', 'WRIST', 'Integrity of radial & ulnar arteries supplying hand', 'CL opens & closes hand, holds fist. Therapist places thumbs over radial & ulnar arteries applying pressure. CL opens fist – release one artery, repeat other side', 'Hand remains pale / wrist tingling or pain', 'Diagnostic criteria not met for Allen’s Test', 'https://www.youtube.com/watch?v=lE16I9S8q8g', 'https://img.youtube.com/vi/lE16I9S8q8g/maxresdefault.jpg'),
(15, 'Cyriax Variation of Phalen’s', 'WRIST', 'Carpal Tunnel Syndrome', 'Perform Phalen’s; at end of 1 min have CL forcefully extend wrists (quick & hard flick)', 'Tingling/pain in thumb, index, middle & lateral ½ of ring finger', 'Diagnostic criteria not met for Cyriax Variation of Phalen’s', 'https://www.youtube.com/watch?v=TMAD-dhT9PM', 'https://img.youtube.com/vi/TMAD-dhT9PM/maxresdefault.jpg'),
(16, 'Degree of Dupuytren’s Contracture', 'WRIST', 'Degree of flexion contractures in Dupuytren’s', 'Add degrees of active free flexion at MCP, PIP, DIP joints of affected digit', 'Stage 0 – no deformity; Stage 1 – 0–45° MCP; Stage 2 – 46–90° PIP; Stage 3 – 91–155° DIP; Stage 4 – >135° DIPs hyperextended', 'Diagnostic criteria not met for Degree of Dupuytren’s Contracture', 'https://www.youtube.com/watch?v=Ztb2xSr4bgk', 'https://img.youtube.com/vi/Ztb2xSr4bgk/maxresdefault.jpg'),
(17, 'Finkelstein’s', 'WRIST', 'DeQuervain’s Tenosynovitis', 'CL seated, make fist with thumb tucked in. Stabilize proximal wrist with one hand, deviate wrist', 'Pain along abductor pollicis longus & extensor pollicis brevis tendon at wrist', 'Diagnostic criteria not met for Finkelstein’s', 'https://www.youtube.com/watch?v=J2lqC1K66iA', 'https://img.youtube.com/vi/J2lqC1K66iA/maxresdefault.jpg'),
(18, 'Froment’s', 'WRIST', 'Ulnar nerve lesion', 'CL grasps paper between thumb & index; therapist pulls paper away', 'Flexion of distal phalanx of thumb (adductor pollicis weakness)', 'Diagnostic criteria not met for Froment’s', '''', ''''),
(19, 'Phalen’s', 'WRIST', 'Carpal Tunnel Syndrome', 'CL seated, backs of hands together, fingers down. Push in & hold 1 min', 'Tingling/pain in thumb, index, middle & lateral ½ of ring finger', 'Diagnostic criteria not met for Phalen’s', 'https://www.youtube.com/watch?v=TMAD-dhT9PM', 'https://img.youtube.com/vi/TMAD-dhT9PM/maxresdefault.jpg'),
(20, 'Pinch Grip Test', 'WRIST', 'Lesion or entrapment in anterior interosseous nerve', 'CL seated, pinch tip of thumb to tip of index finger', 'Unable to pinch tip-to-tip; uses pads instead', 'Diagnostic criteria not met for Pinch Grip Test', '''', ''''),
(21, 'Radial Ligamentous Stress Test', 'WRIST', 'Sprain of Ulnar Collateral Ligament', 'CL seated, arm supinated supported by table; stabilize proximal wrist; move wrist into radial deviation with overpressure', 'Pain or excessive movement', 'Diagnostic criteria not met for Radial Ligamentous Stress Test', '''', ''''),
(22, 'Reversed Phalen’s', 'WRIST', 'Carpal Tunnel Syndrome', 'CL places palms together, fingers pointing up (prayer position). Hold for 1 min', 'Tingling/pain in thumb, index, middle & lateral ½ of ring finger', 'Diagnostic criteria not met for Reversed Phalen’s', 'https://www.youtube.com/watch?v=gT8v8vQxW8M', 'https://img.youtube.com/vi/gT8v8vQxW8M/maxresdefault.jpg'),
(23, 'Sweater Finger Sign', 'WRIST', 'Integrity of Flexor Digitorum Profundus tendon', 'CL makes a fist', 'If 1 finger (usually ring) remains extended at DIP', 'Diagnostic criteria not met for Sweater Finger Sign', 'https://www.youtube.com/watch?v=0kF_M8Yp0iM', 'https://img.youtube.com/vi/0kF_M8Yp0iM/maxresdefault.jpg'),
(24, 'Tinel’s Wrist', 'WRIST', 'Integrity of Median Nerve', 'Therapist taps carpal tunnel', 'Tingling/numbness in median nerve distribution', 'Diagnostic criteria not met for Tinel’s Wrist', 'https://www.youtube.com/watch?v=SOHdFU3hllE', 'https://img.youtube.com/vi/SOHdFU3hllE/maxresdefault.jpg'),
(25, 'Ulnar Ligamentous Stress Test', 'WRIST', 'Sprain of Radial Collateral Ligament', 'CL seated, arm supinated supported; stabilize proximal wrist; move wrist into ulnar deviation with overpressure', 'Pain or excessive movement', 'Diagnostic criteria not met for Ulnar Ligamentous Stress Test', '''', ''''),
(26, 'Adam’s Position', 'SPINE', 'Determine if spinal curve is functional or structural', 'CL standing, bend forward with arms hanging, then laterally bend torso both sides', 'Curve or rib hump corrects/reverses = functional; no change = structural', 'Diagnostic criteria not met for Adam’s Position', 'https://www.youtube.com/watch?v=lZ2a8g-y4F4', 'https://img.youtube.com/vi/lZ2a8g-y4F4/maxresdefault.jpg'),
(27, 'Anterior Spinous Challenge', 'SPINE', 'Determine location of minor vertebral derangement (coronal plane)', 'CL prone, thumbs over individual SP, apply slow anterior pressure T1–L5', 'Pain at specific area; movement = hypo or hyper', 'Diagnostic criteria not met for Anterior Spinous Challenge', '''', ''''),
(28, 'Kemp’s', 'SPINE', 'Block in dural tube, facet joint irritation, SOL', 'CL standing, arms at side, reach hand to back of leg & extend; support from behind', 'Sharp, shooting pain in back & down posterior leg', 'Diagnostic criteria not met for Kemp’s', 'https://www.youtube.com/watch?v=kYJv5_Yt5Ww', 'https://img.youtube.com/vi/kYJv5_Yt5Ww/maxresdefault.jpg'),
(29, 'Keurig’s / Soto Hall', 'SPINE', 'SOL on spine', 'CL supine, tuck chin & flex spine (chin to chest)', 'Sharp, shooting pain down back', 'Diagnostic criteria not met for Keurig’s / Soto Hall', 'https://www.youtube.com/watch?v=Kz023D8Q_mQ', 'https://img.youtube.com/vi/Kz023D8Q_mQ/maxresdefault.jpg'),
(30, 'Lateral Spinous Challenge', 'SPINE', 'Determine location of minor vertebral derangement (sagittal plane)', 'CL prone, thumbs on lateral border of spine, apply slow pressure on SP', 'Pain at specific area; movement = hypo or hyper', 'Diagnostic criteria not met for Lateral Spinous Challenge', '''', ''''),
(31, 'Levator Costarum Fixation', 'SPINE', 'Assess length of individual levator costarum mm', 'CL prone, assess rib mobility; rotate hand to unaffected side; stabilize SP; apply pressure inferiorly & laterally to posterior angle of rib', 'Leathery end feel & tenderness', 'Diagnostic criteria not met for Levator Costarum Fixation', '''', ''''),
(32, 'Milgram’s Sign', 'SPINE', 'LS joint dysfunction', 'CL supine, legs straight; lift both legs 5–10 cm off table & hold 30 sec', 'Inability to hold or symptoms reproduced', 'Diagnostic criteria not met for Milgram’s Sign', 'https://www.youtube.com/watch?v=YxM8FzP1pGg', 'https://img.youtube.com/vi/YxM8FzP1pGg/maxresdefault.jpg'),
(33, 'Passive Scapular Approximation', 'SPINE', 'T1 or T2 nerve root issue', 'CL prone, passively approximate scapulae by lifting shoulders up & back', 'Pain in scapular area', 'Diagnostic criteria not met for Passive Scapular Approximation', '''', ''''),
(34, 'Quadrant (Kemp’s with overpressure)', 'SPINE', 'Block in dural tube, facet joint irritation, SOL', 'CL standing, reach back & extend as far as possible; apply overpressure at end ROM', 'Sharp, shooting pain in back & down posterior leg', 'Diagnostic criteria not met for Quadrant (Kemp’s with overpressure)', '''', ''''),
(35, 'Rebound Tenderness', 'SPINE', 'Appendicitis', 'CL supine; find McBurney’s point (½ way between umbilicus & ASIS); press slowly with breath, quick release', 'Severe pain during release', 'Diagnostic criteria not met for Rebound Tenderness', '''', ''''),
(36, 'Scoliosis', 'SPINE', 'Determine if functional hemipelvis creates spinal curve', 'CL seated; observe iliac crest/AC joint levels; note lateral tilt; place lift under lower side', 'Curve neutralizes = functional scoliosis due to hemipelvis', 'Diagnostic criteria not met for Scoliosis', '''', ''''),
(37, 'Scoliosis Short Leg', 'SPINE', 'Determine if leg length is creating spinal curve', 'CL standing; observe iliac crest/AC joint levels; note tilt; place foot on lifted surface under short leg', 'Curve neutralizes = functional scoliosis due to short leg', 'Diagnostic criteria not met for Scoliosis Short Leg', '''', ''''),
(38, 'Eden’s', 'SHOULDER', 'TOS – Clavicle & 1st rib', 'CL seated, find pulse. CL actively depresses & retracts scapula of affected arm', 'Symptoms recur OR pulse diminished', 'Diagnostic criteria not met for Eden’s', '''', ''''),
(39, 'Empty Can / Supraspinatus Strength', 'SHOULDER', 'Tendonitis, strain, weakness of supraspinatus', 'CL seated, abduct to 90°, horizontally adduct 30°, internally rotate (empty can). If no pain, apply downward pressure', 'Pain along supraspinatus or weakness compared bilaterally', 'Diagnostic criteria not met for Empty Can / Supraspinatus Strength', 'https://www.youtube.com/watch?v=_3MMKHqoZrs', 'https://img.youtube.com/vi/_3MMKHqoZrs/maxresdefault.jpg'),
(40, 'Halstead’s Maneuver', 'SHOULDER', 'TOS – neurovascular compression', 'Palpate radial pulse. CL rotates head away from side being tested & extends head; then ER & extends shoulder. CL takes deep breath & holds 30 sec', 'Pulse disappears or sharp/shooting pain down arm', 'Diagnostic criteria not met for Halstead’s Maneuver', 'https://www.youtube.com/watch?v=p6Q-fT6Yg14', 'https://img.youtube.com/vi/p6Q-fT6Yg14/maxresdefault.jpg'),
(41, 'Hawkins-Kennedy', 'SHOULDER', 'Overuse injury to supraspinatus tendon', 'CL seated, flex arm to 90°, elbow bent 90°, medially rotate shoulder', 'Pain in acromion/tendon area', 'Diagnostic criteria not met for Hawkins-Kennedy', 'https://www.youtube.com/watch?v=X9YiuvQJVJc', 'https://img.youtube.com/vi/X9YiuvQJVJc/maxresdefault.jpg'),
(42, 'Impingement Test', 'SHOULDER', 'Anterior Impingement Syndrome', 'CL seated, take arm to 90° abduction with elbow bent, fully internally rotate (hand back)', 'Reproduction of symptoms (anterior or posterior shoulder pain)', 'Diagnostic criteria not met for Impingement Test', '''', ''''),
(43, 'Jerk Test', 'SHOULDER', 'Posterior Instability', 'CL seated, shoulder flexed 90°, internally rotated, elbow flexed 90°. Apply axial load then horizontally adduct', 'Sudden jerk in shoulder during horizontal adduction', 'Diagnostic criteria not met for Jerk Test', '''', ''''),
(44, 'Lippman’s Test', 'SHOULDER', 'Bicipital tendonitis', 'CL seated, elbows flexed 90°, thumb on biceps tendon, move side to side in groove', 'Sharp pain in tendon groove', 'Diagnostic criteria not met for Lippman’s Test', '''', ''''),
(45, 'Ludington’s (“arrest position”)', 'SHOULDER', 'Rupture of long head of biceps tendon', 'CL seated, stand behind. CL places hands behind head. Therapist palpates groove while CL contracts biceps', 'No movement = Grade 3 strain/rupture of long head', 'Diagnostic criteria not met for Ludington’s (“arrest position”)', 'https://www.youtube.com/watch?v=4NMeI7dMjt4', 'https://img.youtube.com/vi/4NMeI7dMjt4/maxresdefault.jpg'),
(46, 'Neer Impingement', 'SHOULDER', 'Overuse injury to supraspinatus tendon', 'CL seated, passively flex shoulder fully & internally rotate humerus (arm bent for ease)', 'Pain in acromion/tendon area', 'Diagnostic criteria not met for Neer Impingement', 'https://www.youtube.com/watch?v=BudmGMD4CxM', 'https://img.youtube.com/vi/BudmGMD4CxM/maxresdefault.jpg'),
(47, 'O’Brien’s Test', 'SHOULDER', 'SLAP – Superior labral lesion', 'CL standing, flex to 90°, elbow extended, slight horizontal adduction & medial rotation (thumb down). Apply downward force. Repeat palms up', 'Pain at joint line or painful clicking in first position; reduced pain in second', 'Diagnostic criteria not met for O’Brien’s Test', 'https://www.youtube.com/watch?v=Lz4d0e2C1bF', 'https://img.youtube.com/vi/Lz4d0e2C1bF/maxresdefault.jpg'),
(48, 'O’Driscoll’s', 'SHOULDER', 'SLAP – Superior labral lesion', 'CL seated, arm abducted, elbow bent 90°, push on back of shoulder. Raise & lower arm 70–120°', 'Pain & possible clicking between 90–120°', 'Diagnostic criteria not met for O’Driscoll’s', '''', ''''),
(49, 'Acromioclavicular Shear Test', 'SHOULDER', 'Integrity of AC Joint', 'CL seated; therapist stands beside, cups hand over shoulder, interlaces fingers, squeezes heels of hands together (“sellinacat hands”)', 'Pain or excessive movement', 'Diagnostic criteria not met for Acromioclavicular Shear Test', 'https://www.youtube.com/watch?v=s5R-u-Lp1C0', 'https://img.youtube.com/vi/s5R-u-Lp1C0/maxresdefault.jpg'),
(50, 'Adhesive Capsulitis', 'SHOULDER', 'Frozen Shoulder', 'CL seated, stand behind; palpate inferior angle of scapula; other hand just above elbow; slowly abduct humerus & note when angle starts to move', 'Painful, leathery end feel before 90°', 'Diagnostic criteria not met for Adhesive Capsulitis', 'https://www.youtube.com/watch?v=b9cKgwnFIAw', 'https://img.youtube.com/vi/b9cKgwnFIAw/maxresdefault.jpg'),
(51, 'Adson’s (Scalene Maneuver)', 'SHOULDER', 'TOS – neurovascular bundle compression', 'Palpate radial pulse. CL rotates head toward side being tested & extends head; then ER & extends shoulder. CL takes deep breath & holds 30 sec', 'Pulse disappears or sharp/shooting pain down arm', 'Diagnostic criteria not met for Adson’s (Scalene Maneuver)', 'https://www.youtube.com/watch?v=kY0wU33yE38', 'https://img.youtube.com/vi/kY0wU33yE38/maxresdefault.jpg'),
(52, 'Allen’s Maneuver', 'SHOULDER', 'TOS – Pec Minor', 'CL seated; find pulse; passively abduct arm to 90°, slight extension & lateral rotation; CL rotates head away', 'Symptoms recur OR pulse diminished', 'Diagnostic criteria not met for Allen’s Maneuver', '''', ''''),
(53, 'Anterior Apprehension', 'SHOULDER', 'Anterior Shoulder Subluxation/Dislocation', 'CL supine; passively abduct shoulder 90°, add external rotation; support joint; if history of dislocation, repeat with posterior force on humeral head', 'Apprehension with resistance to further motion', 'Diagnostic criteria not met for Anterior Apprehension', 'https://www.youtube.com/watch?v=jZ29dAXKA5M', 'https://img.youtube.com/vi/jZ29dAXKA5M/maxresdefault.jpg'),
(54, 'Anterior Drawer', 'SHOULDER', 'Anterior Instability', 'CL supine; passively abduct 80–120°, forward flex 20°, lateral rotation 30°; brace clavicle/spine of scapula; move humerus forward', 'Excessive movement / apprehension', 'Diagnostic criteria not met for Anterior Drawer', '''', ''''),
(55, 'Apley’s Scratch', 'SHOULDER', 'General GH restrictions of movement', 'CL seated; reach one arm up & back; other arm down & back; compare bilaterally', 'Abduction restriction overhead OR adduction restriction behind back', 'Diagnostic criteria not met for Apley’s Scratch', 'https://www.youtube.com/watch?v=kYJqD0L5uA0', 'https://img.youtube.com/vi/kYJqD0L5uA0/maxresdefault.jpg'),
(56, 'Clunk Test', 'SHOULDER', 'Glenoid Labral Tear', 'CL supine, shoulder fully abducted; grasp distal humerus; move humeral head anteriorly while externally rotating', 'Clunk or grinding at GH joint', 'Diagnostic criteria not met for Clunk Test', '''', ''''),
(57, 'Eden’s (Costoclavicular / Military Brace)', 'SHOULDER', 'TOS – compression between 1st rib & clavicle', 'Palpate radial pulse. CL pulls shoulders back & down (military brace) while protruding chest; holds 30 sec', 'Pulse disappears or sharp/shooting pain down arm', 'Diagnostic criteria not met for Eden’s (Costoclavicular / Military Brace)', 'https://www.youtube.com/watch?v=Gk5s0I6lK_g', 'https://img.youtube.com/vi/Gk5s0I6lK_g/maxresdefault.jpg'),
(58, 'Drop Arm Test', 'SHOULDER', 'Integrity of Rotator Cuff', 'CL standing; passively abduct to 90°; CL slowly lowers arm', 'Unable to return slowly OR severe pain', 'Diagnostic criteria not met for Drop Arm Test', 'https://www.youtube.com/watch?v=52sS3g1-2C0', 'https://img.youtube.com/vi/52sS3g1-2C0/maxresdefault.jpg'),
(59, 'Painful Arc', 'SHOULDER', 'Subacromial impingement of supraspinatus tendon & subacromial bursa', 'CL actively & slowly abducts shoulder through full range (bilaterally)', 'Pain between 45–60° and disappears after 120° = impingement; pain 170–180° = AC joint', 'Diagnostic criteria not met for Painful Arc', 'https://www.youtube.com/watch?v=R_bFw9tq2Jk', 'https://img.youtube.com/vi/R_bFw9tq2Jk/maxresdefault.jpg'),
(60, 'Posterior Drawer', 'SHOULDER', 'Posterior Instability', 'CL supine, arm at shoulder level; flex elbow 120°, abduct 80–120°, forward flex 20–30°; brace clavicle/scapula; medially rotate; push humerus posteriorly', 'Excessive posterior movement of humeral head, apprehension and/or pain', 'Diagnostic criteria not met for Posterior Drawer', '''', ''''),
(61, 'Reverse Impingement Sign', 'SHOULDER', 'Impingement Syndromes', 'CL performs motion that causes impingement; therapist depresses shoulder during action', 'Decrease in pain intensity with depression', 'Diagnostic criteria not met for Reverse Impingement Sign', '''', ''''),
(62, 'Rockwood Test', 'SHOULDER', 'Anterior Instability', 'CL seated, therapist behind; passively externally rotate; arm at 0°, 45°, 90°, 120°', 'No apprehension at 0°; apprehension/pain at 45° & 120°; significant at 90°', 'Diagnostic criteria not met for Rockwood Test', '''', ''''),
(63, 'Roos', 'SHOULDER', 'TOS – General', 'CL seated; abduct arms to 90°, externally rotate; flex elbows 90°; slight extension; open/close hands slowly for 3 min', 'Inability to hold position; ischemic pain, heaviness, weakness, numbness/tingling in hand', 'Diagnostic criteria not met for Roos', 'https://www.youtube.com/watch?v=0oGGdcQsBKY', 'https://img.youtube.com/vi/0oGGdcQsBKY/maxresdefault.jpg'),
(64, 'Speed’s', 'SHOULDER', 'Biceps Tendonitis', 'CL seated, elbow extended, arm supinated; therapist stabilizes & resists shoulder flexion', 'Pain at biceps tendon groove', 'Diagnostic criteria not met for Speed’s', 'https://www.youtube.com/watch?v=410T9R3d6b0', 'https://img.youtube.com/vi/410T9R3d6b0/maxresdefault.jpg'),
(65, 'Sulcus Sign', 'SHOULDER', 'Inferior Instability', 'CL seated, arm relaxed; apply downward pull', 'Visible sulcus', 'Diagnostic criteria not met for Sulcus Sign', 'https://www.youtube.com/watch?v=w0t1qMv2bZc', 'https://img.youtube.com/vi/w0t1qMv2bZc/maxresdefault.jpg'),
(66, 'Tinel’s Shoulder', 'SHOULDER', 'Compression/Irritation of Brachial Plexus', 'CL seated; percussion/tapping over neurovascular bundle (scalene triangle)', 'Reproduction of symptoms in dermatomal pattern', 'Diagnostic criteria not met for Tinel’s Shoulder', 'https://www.youtube.com/watch?v=n9nJt59Qj9U', 'https://img.youtube.com/vi/n9nJt59Qj9U/maxresdefault.jpg'),
(67, 'Travell’s Variation of Adson’s', 'SHOULDER', 'TOS – Middle Scalenes', 'CL seated; find pulse; extend arm slightly & externally rotate; head away & slight elevation; deep breath hold 15–30 sec', 'Symptoms recur OR pulse diminished', 'Diagnostic criteria not met for Travell’s Variation of Adson’s', '''', ''''),
(68, 'ULTT 1 (Median Nerve Bias)', 'SHOULDER', 'Assess for median nerve tension/irritation', 'CL supine. Depress scapula, abduct shoulder 110°, extend wrist/fingers, supinate forearm, extend elbow', 'Reproduction of symptoms, difference compared bilaterally', 'Diagnostic criteria not met for ULTT 1 (Median Nerve Bias)', 'https://www.youtube.com/watch?v=vV1p8s9dD1k', 'https://img.youtube.com/vi/vV1p8s9dD1k/maxresdefault.jpg'),
(69, 'Anterior Drawer', 'ANKLE', 'Integrity of ATFL', 'CL supine with foot relaxed. Stabilize tibia & fibula (hand on top), draw talus forward (hand under ankle)', 'Pain or excessive movement', 'Diagnostic criteria not met for Anterior Drawer', 'https://www.youtube.com/watch?v=6e9e_V20w2I', 'https://img.youtube.com/vi/6e9e_V20w2I/maxresdefault.jpg'),
(70, 'Anterior Talofibular Ligamentous Stress', 'ANKLE', 'Instability/Laxity of ATFL', 'CL supine, stabilize foot in neutral. Grasp calcaneus & move ankle into inversion', 'Pain or excessive movement', 'Diagnostic criteria not met for Anterior Talofibular Ligamentous Stress', 'https://www.youtube.com/watch?v=Q-d0wE1_G4I', 'https://img.youtube.com/vi/Q-d0wE1_G4I/maxresdefault.jpg'),
(71, 'Babinski’s', 'ANKLE', 'CNS Lesions', 'CL supine, run pointed object along plantar aspect of foot quickly', 'Extension of big toe & abduction of other toes', 'Diagnostic criteria not met for Babinski’s', 'https://www.youtube.com/watch?v=pD4XJ_a3Y2k', 'https://img.youtube.com/vi/pD4XJ_a3Y2k/maxresdefault.jpg'),
(72, 'Calcaneocuboid Ligamentous Stress', 'ANKLE', 'Integrity of Calcaneocuboid Ligament', 'CL seated, foot off table. Stabilize calcaneus; supinate & adduct affected forefoot with overpressure at end PROM', 'Pain or excessive movement', 'Diagnostic criteria not met for Calcaneocuboid Ligamentous Stress', '''', ''''),
(73, 'Calcaneofibular Ligamentous Stress / Talar Tilt (Inversion)', 'ANKLE', 'Integrity of Calcaneofibular Ligament', 'CL supine, stabilize distal tib/fib. Grasp calcaneus & invert hindfoot with overpressure at end ROM', 'Pain or excessive movement', 'Diagnostic criteria not met for Calcaneofibular Ligamentous Stress / Talar Tilt (Inversion)', 'https://www.youtube.com/watch?v=2tXq2xM3g6c', 'https://img.youtube.com/vi/2tXq2xM3g6c/maxresdefault.jpg'),
(74, 'Deltoid Ligamentous Stress / Talar Tilt (Eversion)', 'ANKLE', 'Instability/Laxity of Deltoid Ligament', 'CL supine, stabilize malleoli neutral. Evert foot (middle), repeat in dorsiflexion – posterior ligament', 'Pain or excessive movement', 'Diagnostic criteria not met for Deltoid Ligamentous Stress / Talar Tilt (Eversion)', 'https://www.youtube.com/watch?v=2tXq2xM3g6c', 'https://img.youtube.com/vi/2tXq2xM3g6c/maxresdefault.jpg'),
(75, 'Functional/Structural Pes Planus', 'ANKLE', 'Determine if pes planus is structural or functional', 'CL standing. Observe arch. Lift foot & see if arch appears', 'Arch restored = functional; no change = structural', 'Diagnostic criteria not met for Functional/Structural Pes Planus', 'https://www.youtube.com/watch?v=1a6N1f6-n20', 'https://img.youtube.com/vi/1a6N1f6-n20/maxresdefault.jpg'),
(76, 'ULTT Clustered - All Nerves', 'SHOULDER', 'Nerve tension in upper limb', 'Series of ULTT tests as cluster', 'Reproduction of symptoms', 'Diagnostic criteria not met for ULTT Clustered - All Nerves', 'https://www.youtube.com/watch?v=vVj4xS3pW1s', 'https://img.youtube.com/vi/vVj4xS3pW1s/maxresdefault.jpg'),
(77, 'Morton’s Neuroma', 'ANKLE', 'Fracture or neuroma between 2nd & 3rd digits', 'CL supine, squeeze both sides of foot so metatarsal bases push together', 'Severe pain between 2nd & 3rd digits', 'Diagnostic criteria not met for Morton’s Neuroma', '''', ''''),
(78, 'Thompson’s Test', 'ANKLE', 'Rupture of Achilles Tendon', 'CL prone, feet off table; therapist squeezes calf', 'Absence of plantar flexion', 'Diagnostic criteria not met for Thompson’s Test', 'https://www.youtube.com/watch?v=C4u6q39L1h8', 'https://img.youtube.com/vi/C4u6q39L1h8/maxresdefault.jpg'),
(79, 'Tinel’s Tap Sign – Ankle', 'ANKLE', 'Regeneration of Posterior Tibial Nerve', 'CL supine, palpate medial malleolus & slide posterior/inferior to tibial nerve. Tap gently', 'Radicular pain/numbness', 'Diagnostic criteria not met for Tinel’s Tap Sign – Ankle', '''', ''''),
(80, 'Anterior Drawer', 'KNEE', 'Integrity of ACL', 'CL supine, knee 90°, sit on foot, grasp posterior leg, thumbs on joint line, apply gradual anterior force', 'Pain, excessive movement, empty end feel', 'Diagnostic criteria not met for Anterior Drawer', 'https://www.youtube.com/watch?v=R-k345fHn4Q', 'https://img.youtube.com/vi/R-k345fHn4Q/maxresdefault.jpg'),
(81, 'Apley’s Compression', 'KNEE', 'Integrity of Meniscus', 'CL prone, knee flexed 90°, compress & internally/externally rotate', 'Pain in knee', 'Diagnostic criteria not met for Apley’s Compression', 'https://www.youtube.com/watch?v=6Z_9lfX_Pc8', 'https://img.youtube.com/vi/6Z_9lfX_Pc8/maxresdefault.jpg'),
(82, 'Apley’s Distraction', 'KNEE', 'Integrity of Collateral Ligaments', 'CL prone, knee flexed 90°, stabilize tibia; distract & rotate', 'Pain in knee', 'Diagnostic criteria not met for Apley’s Distraction', 'https://www.youtube.com/watch?v=6Z_9lfX_Pc8', 'https://img.youtube.com/vi/6Z_9lfX_Pc8/maxresdefault.jpg'),
(83, 'Bounce Home', 'KNEE', 'Integrity of Meniscus', 'CL supine, knee flexed 90°, extend leg & let go', 'Knee does not fully extend, bounce or jerk', 'Diagnostic criteria not met for Bounce Home', 'https://www.youtube.com/watch?v=Jm-3y4hX9_M', 'https://img.youtube.com/vi/Jm-3y4hX9_M/maxresdefault.jpg'),
(84, 'Patellar Grind', 'KNEE', 'PFPS', 'CL supine, push patella down & superiorly, ask for quad contraction', 'Pain or crepitus', 'Diagnostic criteria not met for Patellar Grind', 'https://www.youtube.com/watch?v=l_6h8xJ7s78', 'https://img.youtube.com/vi/l_6h8xJ7s78/maxresdefault.jpg'),
(85, 'Clarke’s', 'KNEE', 'Patella Femoral Syndrome', 'CL supine, press superior patella into table; contract quad', 'Local sharp pain', 'Diagnostic criteria not met for Clarke’s', 'https://www.youtube.com/watch?v=0G3lP2J2A6c', 'https://img.youtube.com/vi/0G3lP2J2A6c/maxresdefault.jpg'),
(86, 'Coronary Ligamentous Stress Test', 'KNEE', 'Integrity of Coronary Ligaments', 'CL sitting with legs off table, stabilize below knee, move foot med/lat', 'Pain during contraction or inability to contract', 'Diagnostic criteria not met for Coronary Ligamentous Stress Test', '''', ''''),
(87, 'Helfet’s', 'KNEE', 'Integrity of Meniscus', 'CL seated, knee bent, mark mid patella to tibial tuberosity; extend knee', 'Tibial tuberosity does not rotate', 'Diagnostic criteria not met for Helfet’s', '''', ''''),
(88, 'Lachman’s', 'KNEE', 'Integrity of ACL', 'CL supine, flex knee 20–30°; stabilize distal femur; grasp tibia & pull forward', 'Mushy/soft end feel, excessive movement (disappearance of infrapatellar slope)', 'Diagnostic criteria not met for Lachman’s', 'https://www.youtube.com/watch?v=y5K02y95s_E', 'https://img.youtube.com/vi/y5K02y95s_E/maxresdefault.jpg'),
(89, 'Major Effusion / Ballottable Patella Tap', 'KNEE', 'Edema of Knee Joint', 'CL supine, press down on patella & release', 'Patella floats back up like sponge', 'Diagnostic criteria not met for Major Effusion / Ballottable Patella Tap', 'https://www.youtube.com/watch?v=eX-N2g-GfBw', 'https://img.youtube.com/vi/eX-N2g-GfBw/maxresdefault.jpg'),
(90, 'McConnell’s', 'KNEE', 'Patella Femoral Syndrome', 'CL sitting, knee flexed; pressure at different angles (120°, 90°, 60°, 30°); repeat with medial patella glide', 'Pain relieved during 2nd part of test', 'Diagnostic criteria not met for McConnell’s', '''', ''''),
(91, 'McMurray’s', 'KNEE', 'Meniscal lesion', 'CL supine, knee fully flexed. Medial meniscus: ER tibia then extend knee. Lateral meniscus: IR tibia then extend knee (thumb on jt line)', 'Clicking, clunking, snapping or pain', 'Diagnostic criteria not met for McMurray’s', 'https://www.youtube.com/watch?v=lwDFPAyGGgI', 'https://img.youtube.com/vi/lwDFPAyGGgI/maxresdefault.jpg'),
(92, 'Merke’s Disco', 'KNEE', 'Meniscal Tearing', 'CL standing, one leg flexed 10–20°, rotate body medially/laterally', 'Apprehension, pain, instability', 'Diagnostic criteria not met for Merke’s Disco', '''', ''''),
(93, 'Minor Effusion (Brush/Stroke/Bulge)', 'KNEE', 'Edema of Knee Joint', 'CL supine, stroke superior to inferior patella alternating', 'Fluid movement like boat', 'Diagnostic criteria not met for Minor Effusion (Brush/Stroke/Bulge)', '''', ''''),
(94, 'O’Donahue', 'KNEE', 'ACL, MCL, Medial Meniscus', 'CL supine, leg 45°; compress knee/ankle; rotate med/lat; repeat at 90°', 'Local sharp pain', 'Diagnostic criteria not met for O’Donahue', '''', ''''),
(95, 'Patellar Apprehension', 'KNEE', 'Likelihood of lateral patella dislocation', 'Hands on medial patella, push laterally', 'CL resists / won’t allow test', 'Diagnostic criteria not met for Patellar Apprehension', 'https://www.youtube.com/watch?v=f-G9R3t2YhY', 'https://img.youtube.com/vi/f-G9R3t2YhY/maxresdefault.jpg'),
(96, 'Cervical Compression', 'CERVICAL', 'Compression of cervical nerve roots', 'CL seated, press directly down on top of head', 'Pain radiates into arm', 'Diagnostic criteria not met for Cervical Compression', 'https://www.youtube.com/watch?v=f8_k20SgN84', 'https://img.youtube.com/vi/f8_k20SgN84/maxresdefault.jpg'),
(97, 'Cervical Distraction', 'CERVICAL', 'Integrity of cervical spine nerve roots', 'CL seated, hold head and slowly lift (traction) without pulling mandible', 'Pain relieved or decreased', 'Diagnostic criteria not met for Cervical Distraction', 'https://www.youtube.com/watch?v=XW161v3_GkM', 'https://img.youtube.com/vi/XW161v3_GkM/maxresdefault.jpg'),
(98, 'Jackson’s', 'CERVICAL', 'Compression of cervical nerve roots (bilateral)', 'CL seated, rotate head to one side; therapist presses down on head', 'Pain radiates into arm', 'Diagnostic criteria not met for Jackson’s', '''', ''''),
(99, 'Maximum Cervical Compression', 'CERVICAL', 'Compression of cervical nerve roots', 'CL seated, lateral flex head & rotate down; compress; if negative, extend & compress', 'Nerve root = radiating pain; Facet joint = local pain concave side; Muscle spasm = pain convex side', 'Diagnostic criteria not met for Maximum Cervical Compression', '''', ''''),
(100, 'O’Donahue Maneuver', 'CERVICAL', 'Cervical strain or sprain', 'CL seated; therapist moves cervical spine through isometric resisted rotation, then passive rotation bilaterally', 'Pain during resisted = strain; Pain during passive = sprain', 'Diagnostic criteria not met for O’Donahue Maneuver', '''', ''''),
(101, 'Rust Sign', 'CERVICAL', 'Severe muscle strain, ligament instability, disc herniation, cervical fracture/dislocation', 'Visual – CL holds or stabilizes head while moving', 'CL holding head = RED FLAG – Contraindication', 'Diagnostic criteria not met for Rust Sign', '''', ''''),
(102, 'Spurling’s Test', 'CERVICAL', 'Cervical Radiculopathy', 'CL seated, side-bend head to affected side. Apply downward pressure', 'Reproduction of pain in arm', 'Diagnostic criteria not met for Spurling’s Test', 'https://www.youtube.com/watch?v=WzY9s3-a7jY', 'https://img.youtube.com/vi/WzY9s3-a7jY/maxresdefault.jpg'),
(103, 'Scalene Relief', 'CERVICAL', 'Trigger points in scalenes', 'CL seated; bring forearm to rest on head & rotate shoulder forward', 'Pain decreased on same side = TrP in anterior scalene', 'Diagnostic criteria not met for Scalene Relief', '''', ''''),
(104, 'Valsalva Maneuver', 'CERVICAL', 'SOL', 'CL seated, take deep breath & hold while bearing down', 'Pain at site of lesion or radiating down arm', 'Diagnostic criteria not met for Valsalva Maneuver', 'https://www.youtube.com/watch?v=q6d_g_z9K6A', 'https://img.youtube.com/vi/q6d_g_z9K6A/maxresdefault.jpg'),
(105, 'Vertebral Artery Test', 'CERVICAL', 'Integrity of vertebral artery', 'CL supine, shoulders off table; extend, laterally flex & rotate head; count backward from 30', 'Dizziness, visual disturbance (“dancing eyes”) = blockage opposite side – RED FLAG', 'Diagnostic criteria not met for Vertebral Artery Test', 'https://www.youtube.com/watch?v=kR0j9s7d3a0', 'https://img.youtube.com/vi/kR0j9s7d3a0/maxresdefault.jpg'),
(106, 'Cozen’s', 'ELBOW', 'Lateral Epicondylitis (Tennis Elbow)', 'CL seated, forearm pronated & elbow slightly flexed. Stabilize elbow with thumb on lateral epicondyle. CL makes fist and extends wrist radially against resistance (3–4 sec)', 'Sudden severe pain at lateral epicondyle', 'Diagnostic criteria not met for Cozen’s', 'https://www.youtube.com/watch?v=j2Cg3W7fD1I', 'https://img.youtube.com/vi/j2Cg3W7fD1I/maxresdefault.jpg'),
(107, 'Mill’s', 'ELBOW', 'Lateral Epicondylitis (Tennis Elbow)', 'CL seated, stabilize elbow with thumb on lateral epicondyle. Passively flex wrist and fully extend elbow with overpressure', 'Sudden severe pain at lateral epicondyle', 'Diagnostic criteria not met for Mill’s', 'https://www.youtube.com/watch?v=N_a072T9r_Y', 'https://img.youtube.com/vi/N_a072T9r_Y/maxresdefault.jpg'),
(108, 'Medial Epicondylitis Test', 'ELBOW', 'Medial Epicondylitis (Golfer’s Elbow)', 'CL seated, elbow slightly flexed, arm supinated, make fist. Stabilize elbow with thumb on medial epicondyle. Resist wrist flexion', 'Pain at medial epicondyle', 'Diagnostic criteria not met for Medial Epicondylitis Test', 'https://www.youtube.com/watch?v=_0eQz7h6L7s', 'https://img.youtube.com/vi/_0eQz7h6L7s/maxresdefault.jpg'),
(109, 'Golfer’s Elbow', 'ELBOW', 'Medial epicondylitis', 'CL seated/standing, flex elbow; therapist palpates medial epicondyle, supinate arm and extend wrist & elbow', 'Pain at medial epicondyle', 'Diagnostic criteria not met for Golfer’s Elbow', 'https://www.youtube.com/watch?v=_0eQz7h6L7s', 'https://img.youtube.com/vi/_0eQz7h6L7s/maxresdefault.jpg'),
(110, 'Varus Stress Test (Elbow)', 'ELBOW', 'Integrity of Lateral Collateral Ligament (Radial Collateral Ligament)', 'CL seated, slight flexion supported by table. Hand on medial side of joint, other hand lateral side of wrist. Apply force opening lateral joint line', 'Pain or excessive movement', 'Diagnostic criteria not met for Varus Stress Test (Elbow)', 'https://www.youtube.com/watch?v=bO0yX-F2Ejo', 'https://img.youtube.com/vi/bO0yX-F2Ejo/maxresdefault.jpg'),
(111, 'Valgus Stress Test (Elbow)', 'ELBOW', 'Integrity of Medial Collateral Ligament (Ulnar Collateral Ligament)', 'CL seated, slight flexion supported by table. Hand on lateral side of joint, other hand medial side of wrist. Apply force opening medial joint line', 'Pain or excessive movement', 'Diagnostic criteria not met for Valgus Stress Test (Elbow)', 'https://www.youtube.com/watch?v=bO0yX-F2Ejo', 'https://img.youtube.com/vi/bO0yX-F2Ejo/maxresdefault.jpg'),
(112, 'Tinel’s Elbow', 'ELBOW', 'Integrity of Ulnar Nerve', 'Therapist taps ulnar nerve in groove between olecranon & medial epicondyle', 'Tingling sensation along ulnar nerve in arm & hand', 'Diagnostic criteria not met for Tinel’s Elbow', 'https://www.youtube.com/watch?v=hB9i9b-4k_g', 'https://img.youtube.com/vi/hB9i9b-4k_g/maxresdefault.jpg'),
(113, 'ULTT #2 (Betty Boop)', 'ELBOW', 'Integrity of Median, Musculocutaneous & Axillary Nerves', 'CL supine, depress shoulder, hold wrist, abduct shoulder to ~10°, slowly extend wrist & fingers, fully supinate forearm & slowly extend elbow. If no symptoms, lateral flex neck opposite side', 'Recurrence of shoulder/arm pain', 'Diagnostic criteria not met for ULTT #2 (Betty Boop)', 'https://www.youtube.com/watch?v=gX4J7k0d5p0', 'https://img.youtube.com/vi/gX4J7k0d5p0/maxresdefault.jpg'),
(114, 'ULTT #3 (Dad Snacks)', 'ELBOW', 'Integrity of Radial Nerve', 'CL supine, depress shoulder, hold wrist, abduct shoulder to ~10°, slowly extend wrist/fingers, ulnar deviate wrist, fully pronate forearm & slowly extend elbow. If no symptoms, lateral flex neck opposite side', 'Recurrence of shoulder/arm pain', 'Diagnostic criteria not met for ULTT #3 (Dad Snacks)', 'https://www.youtube.com/watch?v=gX4J7k0d5p0', 'https://img.youtube.com/vi/gX4J7k0d5p0/maxresdefault.jpg'),
(115, 'ULTT #4 (Strike a Pose)', 'ELBOW', 'Integrity of C8, T1, Ulnar Nerve', 'CL supine, depress shoulder, hold wrist, abduct shoulder to 90°, slowly flex elbow, supinate forearm, slowly radial deviate wrist. If pain, lateral flex neck opposite side', 'Recurrence of shoulder/arm pain', 'Diagnostic criteria not met for ULTT #4 (Strike a Pose)', 'https://www.youtube.com/watch?v=gX4J7k0d5p0', 'https://img.youtube.com/vi/gX4J7k0d5p0/maxresdefault.jpg'),
(116, 'Wright’s Hyperabduction', 'SHOULDER', 'TOS – Pec Minor', 'CL seated, find pulse, passively abduct affected arm to 180° with slight extension', 'Symptoms recur OR pulse diminished', 'Diagnostic criteria not met for Wright’s Hyperabduction', 'https://www.youtube.com/watch?v=91B3z1Lh_8I', 'https://img.youtube.com/vi/91B3z1Lh_8I/maxresdefault.jpg'),
(117, 'Yergason’s Test (“Hitch Hiker”)', 'SHOULDER', 'Stability of biceps tendon & integrity of transverse humeral ligament', 'CL seated, stabilize elbow against body. Apply resistance as CL supinates forearm, extends elbow & externally rotates shoulder', 'Pain in bicipital groove during resisted movement', 'Diagnostic criteria not met for Yergason’s Test (“Hitch Hiker”)', 'https://www.youtube.com/watch?v=_Wb2V-01Yt4', 'https://img.youtube.com/vi/_Wb2V-01Yt4/maxresdefault.jpg'),
(118, 'SLR – Lasegue’s', 'SPINE', 'SOL in spine, dura or brain; neurologic tension of spinal cord/dura; nerve dysfunction', 'CL supine; passively flex hip, adduct & internally rotate; lift leg to 70°', 'Sharp, shooting pain between 30–70° in leg being tested', 'Diagnostic criteria not met for SLR – Lasegue’s', 'https://www.youtube.com/watch?v=qI3-C7yW2B4', 'https://img.youtube.com/vi/qI3-C7yW2B4/maxresdefault.jpg'),
(119, 'Slump', 'SPINE', 'Spinal Cord Lesion', 'CL seated, hands behind back; slump forward; stick chin out then tuck chin to chest; if no pain extend one knee; if no pain dorsiflex foot', 'Sharp, shooting pain down back & posterior leg', 'Diagnostic criteria not met for Slump', 'https://www.youtube.com/watch?v=8y_Wk5eJbBM', 'https://img.youtube.com/vi/8y_Wk5eJbBM/maxresdefault.jpg'),
(120, 'Trunk & Hip Flexion', 'ELBOW', 'Length of gastrocnemius, hamstrings, upper & lower extensors', 'CL seated, legs straight; reach for toes; observe lateral view; normal = fingertips reach toes, pelvis & ankle neutral', 'Short gastroc = cannot reach due to plantarflexion; Short hamstrings = posterior pelvic tilt & cannot reach; Excess hamstrings = reaches past toes with anterior tilt', 'Diagnostic criteria not met for Trunk & Hip Flexion', '''', ''''),
(121, 'Valsalva', 'ELBOW', 'Effect of ↑ pressure on spinal cord; SOL on spine', 'CL seated; take deep breath & bear down (like blowing balloon)', 'Pain or discomfort due to pressure at spinal level', 'Diagnostic criteria not met for Valsalva', '''', ''''),
(122, 'Posterior Drawer', 'KNEE', 'Integrity of PCL', 'CL supine, knee 90°, sit on foot for stability; thumbs/palms push tibia posteriorly', 'Pain, excessive movement, empty end feel', 'Diagnostic criteria not met for Posterior Drawer', 'https://www.youtube.com/watch?v=n-2P1W1f964', 'https://img.youtube.com/vi/n-2P1W1f964/maxresdefault.jpg'),
(123, 'Posterior Sag Sign', 'KNEE', 'Integrity of PCL', 'CL supine, knee at 90°; observe if tibia sags posteriorly', 'Dip at patella / posterior sag', 'Diagnostic criteria not met for Posterior Sag Sign', 'https://www.youtube.com/watch?v=b4wS9-J6dO8', 'https://img.youtube.com/vi/b4wS9-J6dO8/maxresdefault.jpg'),
(124, 'Valgus & Varus (Knee)', 'KNEE', 'Integrity of Medial & Lateral Collateral Ligaments', 'Valgus: hand at lateral knee, other at medial ankle, press inward. Varus: opposite direction', 'Pain in knee', 'Diagnostic criteria not met for Valgus & Varus (Knee)', 'https://www.youtube.com/watch?v=R9YhE1PqZ5w', 'https://img.youtube.com/vi/R9YhE1PqZ5w/maxresdefault.jpg'),
(125, 'Waldren’s', 'KNEE', 'Patellofemoral Syndrome', 'CL standing; palpate patella while CL bends knees', 'Pain, crepitus, poor patellar tracking', 'Diagnostic criteria not met for Waldren’s', '''', ''''),
(126, 'Wrist Extension Ligamentous Stress Test', 'WRIST', 'Instability of Palmar Radiocarpal Ligaments', 'CL seated, forearm pronated & supported by table. Stabilize proximal hand. Other hand palm-to-palm with CL; passively move wrist into extension with overpressure at end range', 'Pain or excessive movement', 'Diagnostic criteria not met for Wrist Extension Ligamentous Stress Test', 'https://www.youtube.com/watch?v=n7jD9k3vI7w', 'https://img.youtube.com/vi/n7jD9k3vI7w/maxresdefault.jpg'),
(127, 'Wrist Flexion Ligamentous Stress Test', 'WRIST', 'Instability of Dorsal Radiocarpal Ligaments', 'CL seated, forearm pronated & supported by table. Stabilize proximal hand. Other hand palm-to-palm with CL; passively move wrist into flexion with overpressure at end range', 'Pain or excessive movement', 'Diagnostic criteria not met for Wrist Flexion Ligamentous Stress Test', 'https://www.youtube.com/watch?v=u9v2K7aX5gM', 'https://img.youtube.com/vi/u9v2K7aX5gM/maxresdefault.jpg');